// Часовой пояс Екатеринбурга (UTC+5)
const TIMEZONE_OFFSET = 5;

// Получаем текущее время в Екатеринбурге
const now = new Date();
const localTime = new Date(now.getTime() + TIMEZONE_OFFSET * 60 * 60 * 1000);

// Форматируем даты
const formatDate = (date) => {
  const year = date.getUTCFullYear();
  const month = String(date.getUTCMonth() + 1).padStart(2, '0');
  const day = String(date.getUTCDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
};

const formatDateRussian = (date) => {
  const months = ['января', 'февраля', 'марта', 'апреля', 'мая', 'июня', 'июля', 'августа', 'сентября', 'октября', 'ноября', 'декабря'];
  const days = ['воскресенье', 'понедельник', 'вторник', 'среда', 'четверг', 'пятница', 'суббота'];
  return `${date.getUTCDate()} ${months[date.getUTCMonth()]} (${days[date.getUTCDay()]})`;
};

// Сегодня
const today = new Date(localTime);

// Завтра
const tomorrow = new Date(localTime);
tomorrow.setUTCDate(tomorrow.getUTCDate() + 1);

// Послезавтра
const dayAfter = new Date(localTime);
dayAfter.setUTCDate(dayAfter.getUTCDate() + 2);

return {
  json: {
    today: {
      date: formatDate(today),
      readable: formatDateRussian(today)
    },
    tomorrow: {
      date: formatDate(tomorrow),
      readable: formatDateRussian(tomorrow)
    },
    day_after_tomorrow: {
      date: formatDate(dayAfter),
      readable: formatDateRussian(dayAfter)
    },
    message: `Сегодня ${formatDateRussian(today)}. Завтра: ${formatDate(tomorrow)}. Послезавтра: ${formatDate(dayAfter)}.`
  }
};
